package com.example.samlsp.config;

import net.shibboleth.utilities.java.support.component.ComponentInitializationException;
import net.shibboleth.utilities.java.support.xml.BasicParserPool;
import net.shibboleth.utilities.java.support.xml.ParserPool;
import org.opensaml.core.config.ConfigurationService;
import org.opensaml.core.config.InitializationException;
import org.opensaml.core.config.InitializationService;
import org.opensaml.core.xml.config.XMLObjectProviderRegistry;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.annotation.PostConstruct;
import java.util.HashMap;
import java.util.Map;

@Configuration
public class OpenSamlConfig {

    private ParserPool parserPool;

    @PostConstruct
    public void init() throws InitializationException, ComponentInitializationException {
        this.parserPool = createParserPool();

        XMLObjectProviderRegistry registry = new XMLObjectProviderRegistry();
        registry.setParserPool(parserPool);
        ConfigurationService.register(XMLObjectProviderRegistry.class, registry);

        InitializationService.initialize();
    }

    @Bean
    public ParserPool parserPool() {
        return parserPool;
    }

    private ParserPool createParserPool() throws ComponentInitializationException {
        BasicParserPool parserPool = new BasicParserPool();
        parserPool.setMaxPoolSize(100);
        parserPool.setCoalescing(true);
        parserPool.setIgnoreComments(true);
        parserPool.setIgnoreElementContentWhitespace(true);
        parserPool.setNamespaceAware(true);
        parserPool.setExpandEntityReferences(false);
        parserPool.setXincludeAware(false);

        Map<String, Boolean> features = new HashMap<>();
        features.put("http://xml.org/sax/features/external-general-entities", Boolean.FALSE);
        features.put("http://xml.org/sax/features/external-parameter-entities", Boolean.FALSE);
        features.put("http://apache.org/xml/features/disallow-doctype-decl", Boolean.TRUE);
        parserPool.setBuilderFeatures(features);

        parserPool.initialize();
        return parserPool;
    }
}

