package com.example.samlsp.credential;

import com.example.samlsp.config.SamlProperties;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.core.io.DefaultResourceLoader;
import org.springframework.core.io.Resource;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import java.io.BufferedReader;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.stream.Collectors;

@Component
public class CredentialManager {

    private final SamlProperties samlProperties;
    private Credential spCredential;
    private X509Certificate idpCertificate;

    public CredentialManager(SamlProperties samlProperties) {
        this.samlProperties = samlProperties;
    }

    @PostConstruct
    public void init() throws Exception {
        loadSpCredential();
        loadIdpCertificate();
    }

    private void loadSpCredential() throws Exception {
        DefaultResourceLoader resourceLoader = new DefaultResourceLoader();
        Resource keystoreResource = resourceLoader.getResource(samlProperties.getSp().getKeystorePath());

        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = keystoreResource.getInputStream()) {
            keyStore.load(is, samlProperties.getSp().getKeystorePassword().toCharArray());
        }

        String alias = samlProperties.getSp().getKeyAlias();
        PrivateKey privateKey = (PrivateKey) keyStore.getKey(alias,
                samlProperties.getSp().getKeyPassword().toCharArray());
        X509Certificate certificate = (X509Certificate) keyStore.getCertificate(alias);

        BasicX509Credential credential = new BasicX509Credential(certificate, privateKey);
        credential.setEntityId(samlProperties.getSp().getEntityId());
        this.spCredential = credential;
    }

    private void loadIdpCertificate() throws Exception {
        DefaultResourceLoader resourceLoader = new DefaultResourceLoader();
        Resource certResource = resourceLoader.getResource(samlProperties.getIdp().getCertificatePath());

        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        try (InputStream is = certResource.getInputStream()) {
            this.idpCertificate = (X509Certificate) cf.generateCertificate(is);
        }
    }

    public Credential getSpCredential() {
        return spCredential;
    }

    public X509Certificate getSpCertificate() {
        return ((BasicX509Credential) spCredential).getEntityCertificate();
    }

    public X509Certificate getIdpCertificate() {
        return idpCertificate;
    }

    public BasicX509Credential getIdpCredential() {
        return new BasicX509Credential(idpCertificate);
    }
}

