package com.example.samlsp.saml;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.credential.CredentialManager;
import com.example.samlsp.util.SamlUtils;
import org.joda.time.DateTime;
import org.opensaml.core.xml.io.MarshallingException;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.core.AuthnContextClassRef;
import org.opensaml.saml.saml2.core.AuthnContextComparisonTypeEnumeration;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.Issuer;
import org.opensaml.saml.saml2.core.NameIDPolicy;
import org.opensaml.saml.saml2.core.NameIDType;
import org.opensaml.saml.saml2.core.RequestedAuthnContext;
import org.opensaml.security.SecurityException;
import org.opensaml.xmlsec.SignatureSigningParameters;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.opensaml.xmlsec.signature.support.SignatureSupport;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.UUID;

@Component
public class AuthnRequestBuilder {

    private final SamlProperties samlProperties;
    private final CredentialManager credentialManager;

    public AuthnRequestBuilder(SamlProperties samlProperties, CredentialManager credentialManager) {
        this.samlProperties = samlProperties;
        this.credentialManager = credentialManager;
    }

    public AuthnRequest buildAuthnRequest() throws MarshallingException, SecurityException,
            org.opensaml.xmlsec.signature.support.SignatureException {

        AuthnRequest authnRequest = SamlUtils.buildSAMLObject(AuthnRequest.class);
        authnRequest.setID("_" + UUID.randomUUID().toString());
        authnRequest.setIssueInstant(Instant.now());
        authnRequest.setDestination(samlProperties.getIdp().getSsoUrl());
        authnRequest.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        authnRequest.setAssertionConsumerServiceURL(samlProperties.getSp().getAcsUrl());
        authnRequest.setIsPassive(false);
        authnRequest.setForceAuthn(false);

        // Issuer
        Issuer issuer = SamlUtils.buildSAMLObject(Issuer.class);
        issuer.setValue(samlProperties.getSp().getEntityId());
        authnRequest.setIssuer(issuer);

        // NameID Policy
        NameIDPolicy nameIDPolicy = SamlUtils.buildSAMLObject(NameIDPolicy.class);
        nameIDPolicy.setFormat(NameIDType.EMAIL);
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        // Requested AuthnContext
        RequestedAuthnContext requestedAuthnContext = SamlUtils.buildSAMLObject(RequestedAuthnContext.class);
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.MINIMUM);

        AuthnContextClassRef authnContextClassRef = SamlUtils.buildSAMLObject(AuthnContextClassRef.class);
        authnContextClassRef.setURI("urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport");
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        // Sign the request
        signAuthnRequest(authnRequest);

        return authnRequest;
    }

    private void signAuthnRequest(AuthnRequest authnRequest) throws SecurityException,
            MarshallingException, org.opensaml.xmlsec.signature.support.SignatureException {
        SignatureSigningParameters signingParameters = new SignatureSigningParameters();
        signingParameters.setSigningCredential(credentialManager.getSpCredential());
        signingParameters.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signingParameters.setSignatureCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);
        signingParameters.setSignatureReferenceDigestMethod(SignatureConstants.ALGO_ID_DIGEST_SHA256);

        SignatureSupport.signObject(authnRequest, signingParameters);
    }
}

