import org.opensaml.xmlsec.signature.support.SignatureSupport;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.UUID;

@Component
public class LogoutRequestBuilder {

    private final SamlProperties samlProperties;
    private final CredentialManager credentialManager;

    public LogoutRequestBuilder(SamlProperties samlProperties, CredentialManager credentialManager) {
        this.samlProperties = samlProperties;
        this.credentialManager = credentialManager;
    }

    public LogoutRequest buildLogoutRequest(String nameIdValue, String sessionIndexValue)
            throws MarshallingException, SecurityException,
            org.opensaml.xmlsec.signature.support.SignatureException {

        LogoutRequest logoutRequest = SamlUtils.buildSAMLObject(LogoutRequest.class);
        logoutRequest.setID("_" + UUID.randomUUID().toString());
        logoutRequest.setIssueInstant(Instant.now());
        logoutRequest.setDestination(samlProperties.getIdp().getSloUrl());

        Issuer issuer = SamlUtils.buildSAMLObject(Issuer.class);
        issuer.setValue(samlProperties.getSp().getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = SamlUtils.buildSAMLObject(NameID.class);
        nameID.setValue(nameIdValue);
        nameID.setFormat(NameIDType.EMAIL);
        logoutRequest.setNameID(nameID);

        if (sessionIndexValue != null) {
            SessionIndex sessionIndex = SamlUtils.buildSAMLObject(SessionIndex.class);
            sessionIndex.setValue(sessionIndexValue);
            logoutRequest.getSessionIndexes().add(sessionIndex);
        }

        // Sign the request
        SignatureSigningParameters signingParameters = new SignatureSigningParameters();
        signingParameters.setSigningCredential(credentialManager.getSpCredential());
        signingParameters.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signingParameters.setSignatureCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);
        signingParameters.setSignatureReferenceDigestMethod(SignatureConstants.ALGO_ID_DIGEST_SHA256);

        SignatureSupport.signObject(logoutRequest, signingParameters);

        return logoutRequest;
    }
}

