import net.shibboleth.utilities.java.support.xml.ParserPool;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.io.UnmarshallingException;
import org.opensaml.saml.saml2.core.Assertion;
import org.opensaml.saml.saml2.core.Attribute;
import org.opensaml.saml.saml2.core.AttributeStatement;
import org.opensaml.saml.saml2.core.Audience;
import org.opensaml.saml.saml2.core.AudienceRestriction;
import org.opensaml.saml.saml2.core.Conditions;
import org.opensaml.saml.saml2.core.EncryptedAssertion;
import org.opensaml.saml.saml2.core.Response;
import org.opensaml.saml.saml2.core.StatusCode;
import org.opensaml.saml.saml2.core.SubjectConfirmation;
import org.opensaml.saml.saml2.core.SubjectConfirmationData;
import org.opensaml.saml.saml2.encryption.Decrypter;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.encryption.support.DecryptionException;
import org.opensaml.xmlsec.encryption.support.InlineEncryptedKeyResolver;
import org.opensaml.xmlsec.keyinfo.impl.StaticKeyInfoCredentialResolver;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureException;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import java.io.ByteArrayInputStream;
import java.time.Instant;
import java.util.Base64;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Component
public class SamlResponseValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseValidator.class);

    private final SamlProperties samlProperties;
    private final CredentialManager credentialManager;
    private final ParserPool parserPool;

    public SamlResponseValidator(SamlProperties samlProperties,
                                  CredentialManager credentialManager,
                                  ParserPool parserPool) {
        this.samlProperties = samlProperties;
        this.credentialManager = credentialManager;
        this.parserPool = parserPool;
    }

    public SamlResponseData validateResponse(String encodedResponse) throws Exception {
        byte[] decodedBytes = Base64.getDecoder().decode(encodedResponse);
        ByteArrayInputStream inputStream = new ByteArrayInputStream(decodedBytes);

        Document document = parserPool.parse(inputStream);
        Element element = document.getDocumentElement();

        XMLObject xmlObject = SamlUtils.unmarshalElement(element);
        if (!(xmlObject instanceof Response)) {
            throw new SecurityException("Response is not a SAML Response");
        }

        Response response = (Response) xmlObject;

        // Validate status
        validateStatus(response);

        // Validate destination
        validateDestination(response);

        // Validate signature on response if present
        if (response.getSignature() != null) {
            validateSignature(response.getSignature());
        }

        // Get assertions (handle encrypted assertions)
        Assertion assertion = getAssertion(response);

        if (assertion == null) {
            throw new SecurityException("No assertion found in SAML response");
        }

        // Validate assertion signature
        if (assertion.getSignature() != null) {
            validateSignature(assertion.getSignature());
        }

        // Validate conditions
        validateConditions(assertion);

        // Validate subject confirmation
        validateSubjectConfirmation(assertion);

        // Extract user data
        return extractUserData(assertion);
    }

    private void validateStatus(Response response) throws SecurityException {
        if (response.getStatus() == null || response.getStatus().getStatusCode() == null) {
            throw new SecurityException("Response status is missing");
        }
        String statusCode = response.getStatus().getStatusCode().getValue();
        if (!StatusCode.SUCCESS.equals(statusCode)) {
            throw new SecurityException("SAML Response status is not Success: " + statusCode);
        }
    }

    private void validateDestination(Response response) throws SecurityException {
        String destination = response.getDestination();
        if (destination != null && !destination.equals(samlProperties.getSp().getAcsUrl())) {
            throw new SecurityException("Response destination mismatch. Expected: " +
                    samlProperties.getSp().getAcsUrl() + ", Got: " + destination);
        }
    }

    private void validateSignature(Signature signature) throws SecurityException {
        try {
            SignatureValidator.validate(signature, credentialManager.getIdpCredential());
        } catch (SignatureException e) {
            throw new SecurityException("Signature validation failed", e);
        }
    }

    private Assertion getAssertion(Response response) throws DecryptionException {
        // Try unencrypted assertions first
        if (!response.getAssertions().isEmpty()) {
            return response.getAssertions().get(0);
        }

        // Try encrypted assertions
        if (!response.getEncryptedAssertions().isEmpty()) {
            EncryptedAssertion encryptedAssertion = response.getEncryptedAssertions().get(0);
            return decryptAssertion(encryptedAssertion);
        }

        return null;
    }

    private Assertion decryptAssertion(EncryptedAssertion encryptedAssertion) throws DecryptionException {
        StaticKeyInfoCredentialResolver keyInfoCredentialResolver =
                new StaticKeyInfoCredentialResolver(credentialManager.getSpCredential());

        Decrypter decrypter = new Decrypter(null, keyInfoCredentialResolver,
                new InlineEncryptedKeyResolver());
        decrypter.setRootInNewDocument(true);

        return decrypter.decrypt(encryptedAssertion);
    }

    private void validateConditions(Assertion assertion) throws SecurityException {
        Conditions conditions = assertion.getConditions();
        if (conditions == null) {
            return;
        }

        Instant now = Instant.now();

        if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
            throw new SecurityException("Assertion is not yet valid (NotBefore)");
        }

        if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
            throw new SecurityException("Assertion has expired (NotOnOrAfter)");
        }

        // Validate audience restriction
        for (AudienceRestriction audienceRestriction : conditions.getAudienceRestrictions()) {
            boolean validAudience = false;
            for (Audience audience : audienceRestriction.getAudiences()) {
                if (samlProperties.getSp().getEntityId().equals(audience.getURI())) {
                    validAudience = true;
                    break;
                }
            }
            if (!validAudience) {
                throw new SecurityException("SP is not a valid audience for this assertion");
            }
        }
    }

    private void validateSubjectConfirmation(Assertion assertion) throws SecurityException {
        if (assertion.getSubject() == null) {
            throw new SecurityException("Assertion subject is missing");
        }

        boolean validConfirmation = false;
        for (SubjectConfirmation confirmation : assertion.getSubject().getSubjectConfirmations()) {
            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(confirmation.getMethod())) {
                SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
                if (data != null) {
                    Instant now = Instant.now();
                    if (data.getNotOnOrAfter() != null && now.isAfter(data.getNotOnOrAfter())) {
                        continue;
                    }
                    if (data.getRecipient() != null &&
                            !data.getRecipient().equals(samlProperties.getSp().getAcsUrl())) {
                        continue;
                    }
                }
                validConfirmation = true;
                break;
            }
        }

        if (!validConfirmation) {
            throw new SecurityException("No valid subject confirmation found");
        }
    }

    private SamlResponseData extractUserData(Assertion assertion) {
        SamlResponseData data = new SamlResponseData();

        // Extract NameID
        if (assertion.getSubject() != null && assertion.getSubject().getNameID() != null) {
            data.setNameId(assertion.getSubject().getNameID().getValue());
            data.setNameIdFormat(assertion.getSubject().getNameID().getFormat());
        }

        // Extract session index
        if (!assertion.getAuthnStatements().isEmpty()) {
            data.setSessionIndex(assertion.getAuthnStatements().get(0).getSessionIndex());
        }

        // Extract attributes
        Map<String, List<String>> attributes = new HashMap<>();
        for (AttributeStatement attributeStatement : assertion.getAttributeStatements()) {
            for (Attribute attribute : attributeStatement.getAttributes()) {
                String name = attribute.getName();
                List<String> values = attribute.getAttributeValues().stream()
                        .map(XMLObject::getDOM)
                        .filter(dom -> dom != null)
                        .map(dom -> dom.getTextContent())
                        .collect(Collectors.toList());
                attributes.put(name, values);
            }
        }
        data.setAttributes(attributes);

        return data;
    }
}

