package com.example.samlsp.saml;

import java.util.List;
import java.util.Map;

public class SamlResponseData {

    private String nameId;
    private String nameIdFormat;
    private String sessionIndex;
    private Map<String, List<String>> attributes;

    public String getNameId() { return nameId; }
    public void setNameId(String nameId) { this.nameId = nameId; }

    public String getNameIdFormat() { return nameIdFormat; }
    public void setNameIdFormat(String nameIdFormat) { this.nameIdFormat = nameIdFormat; }

    public String getSessionIndex() { return sessionIndex; }
    public void setSessionIndex(String sessionIndex) { this.sessionIndex = sessionIndex; }

    public Map<String, List<String>> getAttributes() { return attributes; }
    public void setAttributes(Map<String, List<String>> attributes) { this.attributes = attributes; }

    public String getFirstAttributeValue(String attributeName) {
        if (attributes != null && attributes.containsKey(attributeName)) {
            List<String> values = attributes.get(attributeName);
            if (values != null && !values.isEmpty()) {
                return values.get(0);
            }
        }
        return null;
    }

    @Override
    public String toString() {
        return "SamlResponseData{" +
                "nameId='" + nameId + '\'' +
                ", nameIdFormat='" + nameIdFormat + '\'' +
                ", sessionIndex='" + sessionIndex + '\'' +
                ", attributes=" + attributes +
                '}';
    }
}

// ========== SP Metadata Generator ==========

package com.example.samlsp.saml;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.credential.CredentialManager;
import com.example.samlsp.util.SamlUtils;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.metadata.AssertionConsumerService;
import org.opensaml.saml.saml2.metadata.EntityDescriptor;
import org.opensaml.saml.saml2.metadata.KeyDescriptor;
import org.opensaml.saml.saml2.metadata.NameIDFormat;
import org.opensaml.saml.saml2.metadata.SPSSODescriptor;
import org.opensaml.saml.saml2.metadata.SingleLogoutService;
import org.opensaml.security.credential.UsageType;
import org.opensaml.xmlsec.keyinfo.impl.X509KeyInfoGeneratorFactory;
import org.opensaml.xmlsec.signature.KeyInfo;
import org.springframework.stereotype.Component;

@Component
public class SpMetadataGenerator {

    private final SamlProperties samlProperties;
    private final CredentialManager credentialManager;

    public SpMetadataGenerator(SamlProperties samlProperties, CredentialManager credentialManager) {
        this.samlProperties = samlProperties;
        this.credentialManager = credentialManager;
    }

    public EntityDescriptor generateMetadata() throws Exception {
        EntityDescriptor entityDescriptor = SamlUtils.buildSAMLObject(EntityDescriptor.class);
        entityDescriptor.setEntityID(samlProperties.getSp().getEntityId());

        SPSSODescriptor spSSODescriptor = SamlUtils.buildSAMLObject(SPSSODescriptor.class);
        spSSODescriptor.setWantAssertionsSigned(true);
        spSSODescriptor.setAuthnRequestsSigned(true);
        spSSODescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        // Key Descriptors
        spSSODescriptor.getKeyDescriptors().add(createKeyDescriptor(UsageType.SIGNING));
        spSSODescriptor.getKeyDescriptors().add(createKeyDescriptor(UsageType.ENCRYPTION));

        // NameID Formats
        NameIDFormat emailFormat = SamlUtils.buildSAMLObject(NameIDFormat.class);
        emailFormat.setURI("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        spSSODescriptor.getNameIDFormats().add(emailFormat);

        NameIDFormat unspecifiedFormat = SamlUtils.buildSAMLObject(NameIDFormat.class);
        unspecifiedFormat.setURI("urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified");
        spSSODescriptor.getNameIDFormats().add(unspecifiedFormat);

        // Assertion Consumer Service
        AssertionConsumerService acsPost = SamlUtils.buildSAMLObject(AssertionConsumerService.class);
        acsPost.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acsPost.setLocation(samlProperties.getSp().getAcsUrl());
        acsPost.setIndex(0);
        acsPost.setIsDefault(true);
        spSSODescriptor.getAssertionConsumerServices().add(acsPost);

        // Single Logout Service
        SingleLogoutService sloPost = SamlUtils.buildSAMLObject(SingleLogoutService.class);
        sloPost.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        sloPost.setLocation(samlProperties.getSp().getSloUrl());
        spSSODescriptor.getSingleLogoutServices().add(sloPost);

        SingleLogoutService sloRedirect = SamlUtils.buildSAMLObject(SingleLogoutService.class);
        sloRedirect.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
        sloRedirect.setLocation(samlProperties.getSp().getSloUrl());
        spSSODescriptor.getSingleLogoutServices().add(sloRedirect);

        entityDescriptor.getRoleDescriptors().add(spSSODescriptor);

        return entityDescriptor;
    }

    private KeyDescriptor createKeyDescriptor(UsageType usageType) throws Exception {
        KeyDescriptor keyDescriptor = SamlUtils.buildSAMLObject(KeyDescriptor.class);
        keyDescriptor.setUse(usageType);

        X509KeyInfoGeneratorFactory keyInfoGeneratorFactory = new X509KeyInfoGeneratorFactory();
        keyInfoGeneratorFactory.setEmitEntityCertificate(true);
        KeyInfo keyInfo = keyInfoGeneratorFactory.newInstance().generate(credentialManager.getSpCredential());
        keyDescriptor.setKeyInfo(keyInfo);

        return keyDescriptor;
    }
}

// ========== SAML HTTP Post Encoder Utility ==========

package com.example.samlsp.saml;

import com.example.samlsp.util.SamlUtils;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.w3c.dom.Element;

import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.ByteArrayOutputStream;
import java.io.StringWriter;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

public class SamlEncoder {

    public static String encodeAuthnRequestForPost(AuthnRequest authnRequest) throws Exception {
        String xml = SamlUtils.xmlObjectToString(authnRequest);
        return Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
    }

    public static String encodeAuthnRequestForRedirect(AuthnRequest authnRequest) throws Exception {
        String xml = SamlUtils.xmlObjectToString(authnRequest);
        byte[] deflated = deflate(xml.getBytes(StandardCharsets.UTF_8));
        String base64 = Base64.getEncoder().encodeToString(deflated);
        return URLEncoder.encode(base64, StandardCharsets.UTF_8.name());
    }

    public static String encodeLogoutRequestForPost(LogoutRequest logoutRequest) throws Exception {
        String xml = SamlUtils.xmlObjectToString(logoutRequest);
        return Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
    }

    private static byte[] deflate(byte[] data) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterStream = new DeflaterOutputStream(baos, deflater);
        deflaterStream.write(data);
        deflaterStream.finish();
        deflaterStream.close();
        return baos.toByteArray();
    }
}

