package com.example.samlsp.security;

import com.example.samlsp.saml.SamlResponseData;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;

import java.util.Collection;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String principal;
    private final SamlResponseData samlResponseData;

    public SamlAuthenticationToken(String principal, SamlResponseData samlResponseData,
                                    Collection<? extends GrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        this.samlResponseData = samlResponseData;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public SamlResponseData getSamlResponseData() {
        return samlResponseData;
    }
}

// ========== SAML User Details ==========

package com.example.samlsp.security;

import com.example.samlsp.saml.SamlResponseData;

import java.io.Serializable;
import java.util.List;
import java.util.Map;

public class SamlUserDetails implements Serializable {

    private static final long serialVersionUID = 1L;

    private String nameId;
    private String email;
    private String firstName;
    private String lastName;
    private String sessionIndex;
    private Map<String, List<String>> attributes;

    public SamlUserDetails(SamlResponseData responseData) {
        this.nameId = responseData.getNameId();
        this.sessionIndex = responseData.getSessionIndex();
        this.attributes = responseData.getAttributes();

        // Map common attributes
        this.email = responseData.getFirstAttributeValue("email");
        if (this.email == null) {
            this.email = responseData.getFirstAttributeValue(
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
        }
        if (this.email == null) {
            this.email = responseData.getNameId();
        }

        this.firstName = responseData.getFirstAttributeValue("firstName");
        if (this.firstName == null) {
            this.firstName = responseData.getFirstAttributeValue(
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname");
        }

        this.lastName = responseData.getFirstAttributeValue("lastName");
        if (this.lastName == null) {
            this.lastName = responseData.getFirstAttributeValue(
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname");
        }
    }

    public String getNameId() { return nameId; }
    public String getEmail() { return email; }
    public String getFirstName() { return firstName; }
    public String getLastName() { return lastName; }
    public String getSessionIndex() { return sessionIndex; }
    public Map<String, List<String>> getAttributes() { return attributes; }
}

// ========== SAML Session Store ==========

package com.example.samlsp.security;

import org.springframework.stereotype.Component;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class SamlSessionStore {

    private final Map<String, SamlUserDetails> sessions = new ConcurrentHashMap<>();
    private final Map<String, String> requestIdToRelayState = new ConcurrentHashMap<>();

    public void storeSession(String sessionId, SamlUserDetails userDetails) {
        sessions.put(sessionId, userDetails);
    }

    public SamlUserDetails getSession(String sessionId) {
        return sessions.get(sessionId);
    }

    public void removeSession(String sessionId) {
        sessions.remove(sessionId);
    }

    public void storeRequestId(String requestId, String relayState) {
        requestIdToRelayState.put(requestId, relayState);
    }

    public String getRelayState(String requestId) {
        return requestIdToRelayState.remove(requestId);
    }
}

// ========== Spring Security Configuration ==========

package com.example.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringRequestMatchers("/saml/acs", "/saml/slo")
                )
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/saml/**", "/saml/metadata", "/saml/login",
                                "/saml/acs", "/saml/slo", "/error", "/health").permitAll()
                        .requestMatchers("/dashboard/**", "/profile/**").authenticated()
                        .anyRequest().authenticated()
                )
                .formLogin(form -> form.disable())
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/")
                );

        return http.build();
    }
}

