package com.example.samlsp.controller;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.saml.*;
import com.example.samlsp.security.SamlAuthenticationToken;
import com.example.samlsp.security.SamlSessionStore;
import com.example.samlsp.security.SamlUserDetails;
import com.example.samlsp.util.SamlUtils;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.opensaml.saml.saml2.metadata.EntityDescriptor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.util.Collections;

@Controller
@RequestMapping("/saml")
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlProperties samlProperties;
    private final AuthnRequestBuilder authnRequestBuilder;
    private final LogoutRequestBuilder logoutRequestBuilder;
    private final SamlResponseValidator samlResponseValidator;
    private final SpMetadataGenerator spMetadataGenerator;
    private final SamlSessionStore samlSessionStore;

    public SamlController(SamlProperties samlProperties,
                           AuthnRequestBuilder authnRequestBuilder,
                           LogoutRequestBuilder logoutRequestBuilder,
                           SamlResponseValidator samlResponseValidator,
                           SpMetadataGenerator spMetadataGenerator,
                           SamlSessionStore samlSessionStore) {
        this.samlProperties = samlProperties;
        this.authnRequestBuilder = authnRequestBuilder;
        this.logoutRequestBuilder = logoutRequestBuilder;
        this.samlResponseValidator = samlResponseValidator;
        this.spMetadataGenerator = spMetadataGenerator;
        this.samlSessionStore = samlSessionStore;
    }

    @GetMapping("/metadata")
    @ResponseBody
    public ResponseEntity<String> metadata() {
        try {
            EntityDescriptor entityDescriptor = spMetadataGenerator.generateMetadata();
            String metadataXml = SamlUtils.xmlObjectToString(entityDescriptor);
            return ResponseEntity.ok()
                    .contentType(MediaType.APPLICATION_XML)
                    .body(metadataXml);
        } catch (Exception e) {
            logger.error("Error generating SP metadata", e);
            return ResponseEntity.internalServerError().body("Error generating metadata");
        }
    }

    @GetMapping("/login")
    public String login(Model model, HttpSession session,
                        @RequestParam(value = "RelayState", required = false) String relayState) {
        try {
            AuthnRequest authnRequest = authnRequestBuilder.buildAuthnRequest();
            String encodedRequest = SamlEncoder.encodeAuthnRequestForPost(authnRequest);

            // Store request ID for validation
            if (relayState == null) {
                relayState = "/dashboard";
            }
            samlSessionStore.storeRequestId(authnRequest.getID(), relayState);

            model.addAttribute("samlRequest", encodedRequest);
            model.addAttribute("idpSsoUrl", samlProperties.getIdp().getSsoUrl());
            model.addAttribute("relayState", relayState);

            return "saml-post-form";
        } catch (Exception e) {
            logger.error("Error initiating SAML login", e);
            return "error";
        }
    }

    @PostMapping("/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            HttpSession session) {
        try {
            logger.info("Received SAML Response at ACS endpoint");

            SamlResponseData responseData = samlResponseValidator.validateResponse(samlResponse);

            logger.info("SAML Response validated successfully. NameID: {}", responseData.getNameId());

            // Create user details
            SamlUserDetails userDetails = new SamlUserDetails(responseData);

            // Create authentication token
            SamlAuthenticationToken authToken = new SamlAuthenticationToken(
                    responseData.getNameId(),
                    responseData,
                    Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER"))
            );

            // Set in security context
            SecurityContextHolder.getContext().setAuthentication(authToken);

            // Store in session
            session.setAttribute("SAML_USER", userDetails);
            samlSessionStore.storeSession(session.getId(), userDetails);

            String redirectUrl = relayState != null ? relayState : "/dashboard";
            return "redirect:" + redirectUrl;

        } catch (Exception e) {
            logger.error("Error processing SAML response", e);
            return "redirect:/error?message=saml_auth_failed";
        }
    }

    @GetMapping("/logout")
    public String singleLogout(Model model, HttpSession session) {
        try {
            SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");

            if (userDetails != null) {
                LogoutRequest logoutRequest = logoutRequestBuilder.buildLogoutRequest(
                        userDetails.getNameId(),
                        userDetails.getSessionIndex()
                );

                String encodedRequest = SamlEncoder.encodeLogoutRequestForPost(logoutRequest);

                model.addAttribute("samlRequest", encodedRequest);
                model.addAttribute("idpSloUrl", samlProperties.getIdp().getSloUrl());
                model.addAttribute("relayState", "/");

                // Clean up local session
                samlSessionStore.removeSession(session.getId());
                session.invalidate();
                SecurityContextHolder.clearContext();

                return "saml-logout-form";
            }

            return "redirect:/";
        } catch (Exception e) {
            logger.error("Error initiating SAML logout", e);
            return "redirect:/error?message=logout_failed";
        }
    }

    @PostMapping("/slo")
    public String singleLogoutCallback(
            @RequestParam(value = "SAMLResponse", required = false) String samlResponse,
            @RequestParam(value = "SAMLRequest", required = false) String samlRequest,
            HttpSession session) {
        try {
            logger.info("Received SLO callback");

            // If this is a logout request from IdP
            if (samlRequest != null) {
                // Process IdP-initiated logout
                samlSessionStore.removeSession(session.getId());
                session.invalidate();
                SecurityContextHolder.clearContext();
                logger.info("IdP-initiated logout processed");
            }

            // If this is a logout response
            if (samlResponse != null) {
                logger.info("Logout response received from IdP");
            }

            return "redirect:/?logout=success";
        } catch (Exception e) {
            logger.error("Error processing SLO callback", e);
            return "redirect:/error?message=slo_failed";
        }
    }
}

// ========== Dashboard Controller ==========

package com.example.samlsp.controller;

import com.example.samlsp.security.SamlAuthenticationToken;
import com.example.samlsp.security.SamlUserDetails;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import javax.servlet.http.HttpSession;

@Controller
public class DashboardController {

    @GetMapping("/")
    public String home() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.isAuthenticated() && auth instanceof SamlAuthenticationToken) {
            return "redirect:/dashboard";
        }
        return "home";
    }

    @GetMapping("/dashboard")
    public String dashboard(Model model, HttpSession session) {
        SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");
        if (userDetails != null) {
            model.addAttribute("user", userDetails);
            model.addAttribute("nameId", userDetails.getNameId());
            model.addAttribute("email", userDetails.getEmail());
            model.addAttribute("firstName", userDetails.getFirstName());
            model.addAttribute("lastName", userDetails.getLastName());
            model.addAttribute("attributes", userDetails.getAttributes());
        }
        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(Model model, HttpSession session) {
        SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");
        if (userDetails != null) {
            model.addAttribute("user", userDetails);
        }
        return "profile";
    }

    @GetMapping("/health")
    @org.springframework.web.bind.annotation.ResponseBody
    public String health() {
        return "{\"status\": \"UP\"}";
    }
}

